def codegen_agent(task: str, max_iterations: int = 5):
    conversation = client.new_conversation()

    for i in range(max_iterations):
        response = conversation.say(task)

        # Extract generated code from structured response
        code = response.tool_calls[0].parameters.get("code", "")

        # Vex verification happens here (see integration section)
        verified_code = vex.verify(code, checks=["code_safety", "syntax_validity"])

        if verified_code.status == "approved":
            result = client.tools["code_sandbox"].execute(verified_code.content)
            if result.tests_passed:
                return verified_code.content

    raise Exception("Max iterations exceeded")

def load_project_context(project_id: str):
    memory_docs = client.memory.search(
        query=f"project:{project_id}",
        limit=10
    )

    context = "\n".join([
        doc.content for doc in memory_docs
        if "code" in doc.metadata.get("type", "")
    ])

    return f"Project context:\n{context}\n\nGenerate next component:"

