def safe_agent_turn(conversation, message):
    raw_response = conversation.say(message)

    # Extract code from response
    code_content = raw_response.content

    # Vex verification with codegen-specific checks
    verification = vex.verify(
        code_content,
        checks=[
            "code_safety",
            "syntax_validity",
            "no_credential_leakage",
            "dependency_safety",
            "execution_sandboxing"
        ],
        context={
            "allowed_packages": ["numpy", "pandas", "requests"],
            "max_exec_time": 30
        }
    )

    if verification.status == "approved":
        return verification.content
    else:
        # Auto-refine on failure
        return conversation.say(f"Fix this code: {code_content}\nIssues: {verification.issues}")

def verified_sandbox_execute(code: str):
    sandbox_check = vex.verify(
        code,
        checks=[
            "execution_sandboxing",
            "no_system_calls",
            "dependency_safety"
        ],
        sandbox_config={
            "memory_limit": "256MB",
            "cpu_limit": "1.0",
            "network": "blocked",
            "allowed_paths": ["/tmp"]
        }
    )

    if sandbox_check.status == "approved":
        return client.tools["code_sandbox"].execute(sandbox_check.content)
    else:
        raise ValueError(f"Sandbox execution blocked: {sandbox_check.issues}")

def scan_for_credentials(code: str, known_secrets: list = None):
    results = vex.verify(
        code,
        checks=["no_credential_leakage", "no_hardcoded_secrets"],
        secrets=known_secrets or [
            "sk-", "ak-", "AWS_ACCESS_KEY"
        ]
    )

    if results.detections:
        clean_code = results.remediated_content
        client.memory.store(
            f"credential_fix_{hash(code)}",
            f"Removed secrets from code"
        )
        return clean_code

    return code
